import React, { useState, useEffect } from 'react';
import { getSeances, getMembersSimple, markPresence, getPresenceForSeance } from '../services/api';

function Presence() {
  const [seances, setSeances] = useState([]);
  const [selectedSeance, setSelectedSeance] = useState('');
  const [membres, setMembres] = useState([]);
  const [presences, setPresences] = useState({}); // { id_membre: 'Présent' | 'Absent' | 'Inscrit' }

  // Charger les séances
  useEffect(() => {
    const fetchData = async () => {
      try {
        const seancesRes = await getSeances();
        setSeances(seancesRes.data || []);
      } catch (err) {
        console.error('Erreur chargement séances:', err);
      }
    };
    fetchData();
  }, []);

  // Quand on change de séance
  const handleSeanceChange = async (e) => {
    const id = e.target.value;
    setSelectedSeance(id);

    if (id) {
      try {
        // Charger les membres
        const membresRes = await getMembersSimple();
        setMembres(membresRes.data || []);

        // Charger les présences existantes
        const presenceRes = await getPresenceForSeance(id);
        const presenceMap = {};
        presenceRes.data.forEach(p => {
          presenceMap[p.id_membre] = p.statut;
        });
        setPresences(presenceMap);
      } catch (err) {
        console.error('Erreur chargement présence:', err);
      }
    }
  };

  // Marquer présence
  const handleMark = async (id_membre, statut) => {
    try {
      await markPresence({ id_seance: selectedSeance, id_membre, statut });
      setPresences(prev => ({ ...prev, [id_membre]: statut }));
      alert(`Statut mis à jour : ${statut}`);
    } catch (err) {
      alert('Erreur lors de l’enregistrement');
      console.error(err);
    }
  };

  return (
    <div className="container mt-4">
      <h2 className="mb-4 text-center">Suivi de Présence</h2>

      {/* Sélection de la séance */}
      <div className="card mb-4 shadow">
        <div className="card-body">
          <label className="form-label fw-bold">Choisir une séance</label>
          <select className="form-select" value={selectedSeance} onChange={handleSeanceChange}>
            <option value="">-- Sélectionner une séance --</option>
            {seances.map(s => (
              <option key={s.id_seance} value={s.id_seance}>
                {s.date} à {s.heure} - {s.nom_sport || 'Sport inconnu'} - Coach : {s.nom_coach || 'Inconnu'}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Tableau des membres + actions */}
      {selectedSeance && (
        <>
          <h4 className="mb-3">Liste des membres</h4>
          <div className="table-responsive">
            <table className="table table-striped table-hover">
              <thead className="table-dark">
                <tr>
                  <th>Nom</th>
                  <th>Prénom</th>
                  <th>Statut actuel</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {membres.map(m => (
                  <tr key={m.id_personne}>
                    <td>{m.nom}</td>
                    <td>{m.prenom}</td>
                    <td className={
                      presences[m.id_personne] === 'Présent' ? 'text-success fw-bold' :
                      presences[m.id_personne] === 'Absent' ? 'text-danger fw-bold' :
                      'text-secondary'
                    }>
                      {presences[m.id_personne] || 'Non inscrit'}
                    </td>
                    <td>
                      <button className="btn btn-success btn-sm me-2" onClick={() => handleMark(m.id_personne, 'Présent')}>
                        Présent
                      </button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleMark(m.id_personne, 'Absent')}>
                        Absent
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}
    </div>
  );
}

export default Presence;
